#include<bits/stdc++.h>
using namespace std;
int d,n,m,a[100007],ans;
bool pan(int x){
    int now=a[1],cnt=0;
    for (int i = 1; i < n; i++) {
        int distance = a[i+1] - a[i];
        if (distance > x) {
            cnt += (distance - 1) / x;
            if (cnt > m) return 0;
        }
    }
    return 1;
}
int main(){
    cin>>d>>n>>m;
    for(int i=1;i<=n;i++) cin>>a[i];
    sort(a+1,a+1+n);
    int l=1,r=d;
    while(l<=r){
        int mid=(l+r)/2;
        if(pan(mid)){
            ans=mid;
             r=mid-1;



        }else{
          l=mid+1;
        }
    }
    cout<<ans;
}
